import{_ as i,c as s,o as t,aN as e}from"./chunks/framework.BRm39z_l.js";const c=JSON.parse('{"title":"MySQL基础","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/01.MySQL基础.md","filePath":"mysql/01.MySQL基础.md"}'),l={name:"mysql/01.MySQL基础.md"};function n(h,a,d,r,p,o){return t(),s("div",null,a[0]||(a[0]=[e(`<h1 id="mysql基础" tabindex="-1">MySQL基础 <a class="header-anchor" href="#mysql基础" aria-label="Permalink to &quot;MySQL基础&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#两张表怎么进行连接">两张表怎么进⾏连接？</a></li><li><a href="#说一下数据库的三大范式">说一下数据库的三大范式？</a><ul><li><a href="#建表的时候需要考虑哪些问题">建表的时候需要考虑哪些问题？</a></li><li><a href="#为什么需要三大范式">为什么需要三大范式？</a></li><li><a href="#不遵循三大范式的场景">不遵循三大范式的场景</a></li></ul></li><li><a href="#varchar-和-char-的区别">varchar 和 char 的区别</a></li><li><a href="#in-和-exists-的区别">in 和 exists 的区别</a></li><li><a href="#记录货币用什么类型">记录货币用什么类型</a></li><li><a href="#drop、delete-与-truncate-的区别">drop、delete 与 truncate 的区别</a></li><li><a href="#查询语句的执行顺序">查询语句的执行顺序</a></li></ul></nav><h2 id="两张表怎么进行连接" tabindex="-1">两张表怎么进⾏连接？ <a class="header-anchor" href="#两张表怎么进行连接" aria-label="Permalink to &quot;两张表怎么进⾏连接？&quot;">​</a></h2><p>可以通过内连接 <code>inner join</code>、外连接 <code>outer join</code>、交叉连接 <code>cross join</code> 来合并多个表的查询结果</p><p>内连接可以用来找出两个表中共同的记录，相当于两个数据集的交集</p><p>定义数据库 A 为</p><table tabindex="0"><thead><tr><th>id</th><th>name</th></tr></thead><tbody><tr><td>1</td><td>张三</td></tr><tr><td>2</td><td>李四</td></tr><tr><td>3</td><td>王五</td></tr></tbody></table><p>定义数据库 B 为：</p><table tabindex="0"><thead><tr><th>id</th><th>score</th></tr></thead><tbody><tr><td>1</td><td>90</td></tr><tr><td>2</td><td>80</td></tr></tbody></table><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INNER JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> A</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> B</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>只有两表中都存在 user_id 的记录才会出现在查询结果中</p><table tabindex="0"><thead><tr><th>id</th><th>name</th><th>score</th></tr></thead><tbody><tr><td>1</td><td>张三</td><td>90</td></tr><tr><td>2</td><td>李四</td><td>80</td></tr></tbody></table><p>左连接和右连接可以用来找出两个表中不同的记录，相当于两个数据集的并集。两者的区别是，左连接会保留左表中符合条件的所有记录，右连接则刚好相反</p><div class="language-SQL vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">SQL</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LEFT JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> A</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> B</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th>id</th><th>name</th><th>score</th></tr></thead><tbody><tr><td>1</td><td>张三</td><td>90</td></tr><tr><td>2</td><td>李四</td><td>80</td></tr><tr><td>3</td><td>王五</td><td>NULL</td></tr></tbody></table><h2 id="说一下数据库的三大范式" tabindex="-1">说一下数据库的三大范式？ <a class="header-anchor" href="#说一下数据库的三大范式" aria-label="Permalink to &quot;说一下数据库的三大范式？&quot;">​</a></h2><p>第一范式，确保表中的<strong>每个字段都是不可再分的原子值</strong></p><table tabindex="0"><thead><tr><th>学生 ID</th><th>姓名</th><th>电话</th></tr></thead><tbody><tr><td>1</td><td>张三</td><td>138xxx, 139xxx</td></tr></tbody></table><p>第二范式，要求非主键字段必须<strong>完全依赖主键</strong>，不能只依赖主键的一部分</p><p>选课表：</p><table tabindex="0"><thead><tr><th>学生 ID</th><th>课程 ID</th><th>学生姓名</th><th>课程名称</th><th>成绩</th><th></th></tr></thead></table><p>主键： (学生 ID, 课程 ID)</p><ul><li>学生姓名 只依赖 学生 ID</li><li>课程名称 只依赖 课程 ID</li></ul><p>第三范式，非主键字段之间不能存在依赖关系，如</p><table tabindex="0"><thead><tr><th>学生 ID</th><th>姓名</th><th>系 ID</th><th>系名称</th><th></th><th></th></tr></thead></table><h3 id="建表的时候需要考虑哪些问题" tabindex="-1">建表的时候需要考虑哪些问题？ <a class="header-anchor" href="#建表的时候需要考虑哪些问题" aria-label="Permalink to &quot;建表的时候需要考虑哪些问题？&quot;">​</a></h3><p>首先需要考虑表是否符合数据库的三大范式，确保字段不可再分，消除非主键依赖，确保字段仅依赖于主键等。</p><p>然后在选择字段类型时，应该尽量选择合适的数据类型。</p><p>在字符集上，尽量选择 utf8mb4，这样不仅可以支持中文和英文，还可以支持表情符号等。</p><p>当数据量较大时，比如上千万行数据，需要考虑分表。比如订单表，可以采用水平分表的方式来分散单表存储压力。</p><h3 id="为什么需要三大范式" tabindex="-1">为什么需要三大范式？ <a class="header-anchor" href="#为什么需要三大范式" aria-label="Permalink to &quot;为什么需要三大范式？&quot;">​</a></h3><p>核心目标是 <strong>减少数据冗余</strong>，避免三种异常：</p><ul><li><strong>更新异常</strong>：修改一处数据需改多处（如改产品名称，所有订单都要改）。</li><li><strong>插入异常</strong>：某些信息无法单独插入（如新增产品但暂无订单，产品信息插不进订单表）。</li><li><strong>删除异常</strong>：删除一条记录意外删除其他信息（如删除最后一个订单，产品信息也被删）。</li></ul><h3 id="不遵循三大范式的场景" tabindex="-1">不遵循三大范式的场景 <a class="header-anchor" href="#不遵循三大范式的场景" aria-label="Permalink to &quot;不遵循三大范式的场景&quot;">​</a></h3><p><strong>例子：电商订单列表页</strong></p><ul><li>需求：快速展示订单中的 「商品名称」「商品单价」（用户高频访问，性能要求高）。</li><li>按 3NF 设计：订单表（订单 ID，商品 ID）+ 商品表（商品 ID，名称，单价），查询时需关联两张表。</li><li>实际优化：直接在订单表中冗余 「商品名称」「商品单价」，避免关联查询，牺牲少量冗余换取查询速度。</li></ul><p><strong>原因</strong>：高并发场景下，关联查询（JOIN）耗时，冗余存储可减少数据库 IO，提升响应速度。此时 「违反范式」 是权衡性能后的合理选择。</p><h2 id="varchar-和-char-的区别" tabindex="-1">varchar 和 char 的区别 <a class="header-anchor" href="#varchar-和-char-的区别" aria-label="Permalink to &quot;varchar 和 char 的区别&quot;">​</a></h2><p>varchar 是可变长度的字符串类型，原则上最多可以容纳 65535 个字符，但考虑字符集，以及 MySQL 需要 1 到 2 个字节来表示字符串长度，所以实际上最大可以设置到 65533</p><p>char 是固定长度的字符类型，当定义一个 <code>CHAR(10)</code> 字段时，不管实际存储的字符长度是多少，都只会占用 10 个字符的空间。如果插入的数据小于 10 个字符，剩余的部分会用空格填充</p><h2 id="in-和-exists-的区别" tabindex="-1">in 和 exists 的区别 <a class="header-anchor" href="#in-和-exists-的区别" aria-label="Permalink to &quot;in 和 exists 的区别&quot;">​</a></h2><p><code>IN</code> 的执行逻辑：子查询优先，结果集匹配</p><ul><li>第一步：先执行<strong>子查询</strong>，得到一个 「单列值列表」（如 <code>(1,2,3)</code>），并临时存储；</li><li>第二步：主查询遍历每一条记录，判断 「主表字段值是否在子查询的列表中」（类似 <code>value IN (a,b,c)</code> 的等值判断）；</li></ul><p><code>EXISTS</code> 的执行逻辑：主查询驱动，关联判断</p><ul><li>第一步：先执行<strong>主查询</strong>，取出一条记录；</li><li>第二步：将这条记录的字段（如 <code>u.id</code>）传入子查询，判断子查询是否能找到匹配记录（如 <code>o.user_id = u.id</code>）；</li><li>第三步：若子查询返回至少一条记录（存在匹配），则主查询保留这条记录；否则丢弃，继续遍历主查询下一条；</li></ul><blockquote><p><code>IN</code>: 如果子查询的结果集中包含 <code>NULL</code> 值，可能会导致意外的结果</p><p><code>EXISTS</code>：只是检查子查询是否返回行，不关心行的具体值，因此不受 <code>NULL</code> 值的影响</p></blockquote><h2 id="记录货币用什么类型" tabindex="-1">记录货币用什么类型 <a class="header-anchor" href="#记录货币用什么类型" aria-label="Permalink to &quot;记录货币用什么类型&quot;">​</a></h2><p>不推荐使用<code>float</code>和<code>double</code>，再某些情况下会存在精度问题</p><p>如果是电商、交易、账单等涉及货币的场景，建议使用 DECIMAL 类型，因为 DECIMAL 类型是精确数值类型，不会出现浮点数计算误差</p><p>例如，<code>DECIMAL(19,4)</code> 可以存储最多 19 位数字，其中 4 位是小数</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> orders</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AUTO_INCREMENT,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    amount </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DECIMAL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">19</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    PRIMARY KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (id)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果是银行，涉及到支付的场景，建议使用 <code>BIGINT </code>类型。可以将货币金额乘以一个固定因子，比如 100，表示以“分”为单位，然后存储为 <code>BIGINT</code>。这种方式既避免了浮点数问题，同时也提供了不错的性能。但在展示的时候需要除以相应的因子</p><h2 id="drop、delete-与-truncate-的区别" tabindex="-1">drop、delete 与 truncate 的区别 <a class="header-anchor" href="#drop、delete-与-truncate-的区别" aria-label="Permalink to &quot;drop、delete 与 truncate 的区别&quot;">​</a></h2><p>DROP 是物理删除，用来删除整张表，包括表结构，且不能回滚</p><p>DELETE 支持行级删除，可以带 WHERE 条件，可以回滚</p><p>TRUNCATE 用于清空表中的所有数据，但会保留表结构，不能回滚</p><h2 id="查询语句的执行顺序" tabindex="-1">查询语句的执行顺序 <a class="header-anchor" href="#查询语句的执行顺序" aria-label="Permalink to &quot;查询语句的执行顺序&quot;">​</a></h2><ol><li>先执行 FROM 确定主表</li><li>再执行 JOIN 连接</li><li>然后 WHERE 进行过滤</li><li>接着 GROUP BY 进行分组</li><li>HAVING 过滤聚合结果</li><li>SELECT 选择最终列</li><li>ORDER BY 排序</li><li>最后 LIMIT 限制返回行数</li></ol><blockquote><p>WHERE 先执行是为了减少数据量，HAVING 只能过滤聚合数据，ORDER BY 必须在 SELECT 之后排序最终结果，LIMIT 最后执行以减少数据传输。</p></blockquote>`,59)]))}const E=i(l,[["render",n]]);export{c as __pageData,E as default};
